    <div>
      <form onSubmit={onSubmit}>
        <h1>To Do List ({toDos.length})</h1>
        <input
          value={toDo}
          onChange={onChange}
          type="text"
          placeholder="Write your ToDo"
        ></input>
        <button>Add ToDo</button>
      </form>
      <hr />
      <ul>
        {toDos.map((item, index) => (
          <li key={index}>{item}</li>
        ))}
      </ul>
    </div>
  );
}

export default App;
